import { useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Loader2, Import, CheckCircle2, AlertCircle } from "lucide-react";
import { useToast } from "@/hooks/use-toast";

const COUNTRIES = [
  { code: "Portugal", label: "🇵🇹 葡萄牙" },
  { code: "Spain", label: "🇪🇸 西班牙" },
  { code: "France", label: "🇫🇷 法国" },
  { code: "Germany", label: "🇩🇪 德国" },
  { code: "Italy", label: "🇮🇹 意大利" },
  { code: "United Kingdom", label: "🇬🇧 英国" },
  { code: "Netherlands", label: "🇳🇱 荷兰" },
  { code: "Japan", label: "🇯🇵 日本" },
  { code: "South Korea", label: "🇰🇷 韩国" },
  { code: "United States", label: "🇺🇸 美国" },
];

interface ImportResult {
  success: boolean;
  country?: string;
  total_found?: number;
  imported?: number;
  skipped?: number;
  errors?: string[];
  dry_run?: boolean;
  award_breakdown?: Record<string, number>;
  sample?: Array<{ name: string; city: string; michelin_stars: string; type_en: string[] }>;
  error?: string;
}

export default function MichelinImportPanel() {
  const { toast } = useToast();
  const [country, setCountry] = useState("Portugal");
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ImportResult | null>(null);

  const handleImport = async (dryRun: boolean) => {
    setLoading(true);
    setResult(null);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) throw new Error("Not authenticated");

      const res = await supabase.functions.invoke("import-michelin-restaurants", {
        body: { country, dry_run: dryRun },
      });

      if (res.error) throw res.error;
      setResult(res.data as ImportResult);

      if (!dryRun && res.data?.imported > 0) {
        toast({
          title: `成功导入 ${res.data.imported} 家米其林餐厅`,
          description: `${country} - 跳过 ${res.data.skipped} 家重复`,
        });
      }
    } catch (err: any) {
      toast({ title: "导入失败", description: err.message, variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Import className="h-5 w-5" />
          米其林餐厅批量导入
        </CardTitle>
        <CardDescription>
          从 GitHub 米其林数据集 (ngshiheng/michelin-my-maps) 批量导入 18,000+ 餐厅数据，包含1-3星、必比登推介等
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="flex items-center gap-3">
          <Select value={country} onValueChange={setCountry}>
            <SelectTrigger className="w-[200px]">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              {COUNTRIES.map(c => (
                <SelectItem key={c.code} value={c.code}>{c.label}</SelectItem>
              ))}
            </SelectContent>
          </Select>
          <Button variant="outline" onClick={() => handleImport(true)} disabled={loading}>
            {loading ? <Loader2 className="h-4 w-4 animate-spin mr-1" /> : null}
            预览
          </Button>
          <Button onClick={() => handleImport(false)} disabled={loading}>
            {loading ? <Loader2 className="h-4 w-4 animate-spin mr-1" /> : <Import className="h-4 w-4 mr-1" />}
            导入
          </Button>
        </div>

        {result && (
          <div className="space-y-3 p-4 rounded-lg border bg-muted/30">
            {result.error ? (
              <div className="flex items-center gap-2 text-destructive">
                <AlertCircle className="h-4 w-4" />
                <span>{result.error}</span>
              </div>
            ) : (
              <>
                <div className="flex items-center gap-2">
                  <CheckCircle2 className="h-4 w-4 text-emerald-500" />
                  <span className="font-medium">
                    {result.dry_run ? '预览结果' : '导入完成'} - {result.country}
                  </span>
                </div>
                <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 text-sm">
                  <div className="p-2 rounded bg-background border">
                    <div className="text-muted-foreground text-xs">总计发现</div>
                    <div className="font-bold text-lg">{result.total_found}</div>
                  </div>
                  {!result.dry_run && (
                    <>
                      <div className="p-2 rounded bg-background border">
                        <div className="text-muted-foreground text-xs">已导入</div>
                        <div className="font-bold text-lg text-emerald-600">{result.imported}</div>
                      </div>
                      <div className="p-2 rounded bg-background border">
                        <div className="text-muted-foreground text-xs">跳过(重复)</div>
                        <div className="font-bold text-lg text-amber-600">{result.skipped}</div>
                      </div>
                    </>
                  )}
                </div>

                {/* Award breakdown */}
                {result.award_breakdown && (
                  <div className="flex flex-wrap gap-2">
                    {result.award_breakdown.three_stars > 0 && (
                      <Badge className="bg-yellow-500/15 text-yellow-700 border-yellow-500/30">⭐⭐⭐ 三星 {result.award_breakdown.three_stars}</Badge>
                    )}
                    {result.award_breakdown.two_stars > 0 && (
                      <Badge className="bg-yellow-500/15 text-yellow-700 border-yellow-500/30">⭐⭐ 二星 {result.award_breakdown.two_stars}</Badge>
                    )}
                    {result.award_breakdown.one_star > 0 && (
                      <Badge className="bg-yellow-500/15 text-yellow-700 border-yellow-500/30">⭐ 一星 {result.award_breakdown.one_star}</Badge>
                    )}
                    {result.award_breakdown.bib_gourmand > 0 && (
                      <Badge className="bg-red-500/15 text-red-700 border-red-500/30">🍽️ 必比登 {result.award_breakdown.bib_gourmand}</Badge>
                    )}
                    {result.award_breakdown.selected > 0 && (
                      <Badge className="bg-orange-500/15 text-orange-700 border-orange-500/30">🌟 入选 {result.award_breakdown.selected}</Badge>
                    )}
                  </div>
                )}

                {/* Sample restaurants */}
                {result.sample && result.sample.length > 0 && (
                  <div className="space-y-1">
                    <div className="text-xs text-muted-foreground font-medium">示例:</div>
                    {result.sample.map((r, i) => (
                      <div key={i} className="text-sm flex items-center gap-2">
                        <span className="font-medium">{r.name}</span>
                        <span className="text-muted-foreground text-xs">{r.city}</span>
                        <Badge variant="outline" className="text-[10px]">{r.michelin_stars}</Badge>
                      </div>
                    ))}
                  </div>
                )}

                {/* Errors */}
                {result.errors && result.errors.length > 0 && (
                  <div className="space-y-1">
                    <div className="text-xs text-destructive font-medium">错误 ({result.errors.length}):</div>
                    {result.errors.slice(0, 5).map((err, i) => (
                      <div key={i} className="text-xs text-destructive">{err}</div>
                    ))}
                  </div>
                )}
              </>
            )}
          </div>
        )}
      </CardContent>
    </Card>
  );
}
