interface DiscoveredRestaurant {
  name: string;
  address: string;
  cuisine_type: string;
  city: string;
  source?: "perplexity" | "firecrawl";
  source_platform?: string;
  google_verified?: boolean;
  corrected_address?: string;
  verified?: boolean;
  story_hint?: string;
  place_id?: string;
}

// ─── Building Categories ────────────────────────────────────────────────────
