export default function AdminDiscoverRestaurants() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [activeMainTab, setActiveMainTab] = useState("search");

  // Search state
  const [selectedCountry, setSelectedCountry] = useState("PT");
  const [selectedCity, setSelectedCity] = useState("all");
  const [selectedCategory, setSelectedCategory] = useState("landmark");
  const [selectedRegion, setSelectedRegion] = useState("asian");
  const [searchKeyword, setSearchKeyword] = useState("");
  const [isSearching, setIsSearching] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [discovered, setDiscovered] = useState<DiscoveredRestaurant[]>([]);
  const [selectedItems, setSelectedItems] = useState<Set<number>>(new Set());
  const [skipCache, setSkipCache] = useState(false);
  const [searchStats, setSearchStats] = useState<{
    total_discovered: number;
    duplicates_filtered: number;
    verified_count?: number;
    source_stats?: { perplexity: number; firecrawl: number };
    cache_hits?: number;
    search_error?: string;
  } | null>(null);
  const [importResults, setImportResults] = useState<{ imported: number; failed: number; duplicates?: number; created?: number; updated?: number; details?: Array<{ name: string; action?: string; error?: string; dedup_reason?: string; success: boolean }> } | null>(null);
  const [importedIds, setImportedIds] = useState<string[]>([]);
  const [importProgress, setImportProgress] = useState({ current: 0, total: 0 });

  // Post-import actions
  const [isGeneratingStories, setIsGeneratingStories] = useState(false);
  const [storyProgress, setStoryProgress] = useState({ current: 0, total: 0 });
  const [storyResult, setStoryResult] = useState<{ processed: number } | null>(null);
  const [isFetchingPhotos, setIsFetchingPhotos] = useState(false);
  const [photoProgress, setPhotoProgress] = useState({ current: 0, total: 0 });
  const [photoResult, setPhotoResult] = useState<{ success: number; failed: number } | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  // (Enrichment moved to DataCheckPanel)

  // Data health query
  const { data: healthData, refetch: refetchHealth } = useQuery({
    queryKey: ["data-health"],
    queryFn: async () => {
      const [totalRes, placeIdRes, zeroRes, landmarkRes, dupNameRes] = await Promise.all([
        supabase.from("restaurants").select("id", { count: "exact", head: true }),
        supabase.from("restaurants").select("id", { count: "exact", head: true }).not("google_place_id", "is", null).neq("google_place_id", ""),
        supabase.from("restaurants").select("id", { count: "exact", head: true }).eq("lat", 0).eq("lng", 0),
        supabase.from("restaurants").select("id", { count: "exact", head: true }).eq("template", "landmark"),
        supabase.from("restaurants").select("id", { count: "exact", head: true }).or("image_url.is.null,image_url.eq."),
      ]);
      return {
        total: totalRes.count || 0,
        hasPlaceId: placeIdRes.count || 0,
        zeroCoords: zeroRes.count || 0,
        landmarks: landmarkRes.count || 0,
        noPhoto: dupNameRes.count || 0,
      };
    },
    staleTime: 1000 * 60 * 5,
    enabled: activeMainTab === "health",
  });

  const countryConfig = useMemo(() => COUNTRIES.find(c => c.code === selectedCountry) || COUNTRIES[0], [selectedCountry]);

  const handleCountryChange = (code: string) => {
    setSelectedCountry(code);
    setSelectedCity("all");
  };

  // ─── Search ───────────────────────────────────────────────────────────────
  const handleSearch = async () => {
    setIsSearching(true);
    setDiscovered([]);
    setSelectedItems(new Set());
    setSearchStats(null);
    setImportResults(null);
    setImportedIds([]);
    setStoryResult(null);
    setPhotoResult(null);

    const controller = new AbortController();
    abortControllerRef.current = controller;

    try {
      const isThematic = selectedCategory !== "";
      const { data, error } = await supabase.functions.invoke("discover-asian-restaurants", {
        body: {
          city: selectedCity,
          mode: "search",
          keyword: searchKeyword.trim() || undefined,
          cuisine_region: !isThematic ? selectedRegion : undefined,
          search_theme: isThematic ? selectedCategory : undefined,
          skip_cache: skipCache,
          country: selectedCountry,
        },
      });

      if (controller.signal.aborted) return;
      if (error) throw error;

      const restaurants: DiscoveredRestaurant[] = data.restaurants || [];
      setDiscovered(restaurants);
      setSearchStats({
        total_discovered: data.total_discovered,
        duplicates_filtered: data.duplicates_filtered,
        verified_count: data.verified_count,
        source_stats: data.source_stats,
        cache_hits: data.cache_hits,
        search_error: data.search_error,
      });
      setSelectedItems(new Set(
        restaurants.map((r, i) => (r.google_verified !== false) ? i : -1).filter(i => i >= 0)
      ));

      // Save search history
      supabase.from("discovery_search_history").insert({
        country: selectedCountry,
        city: selectedCity === "all" ? null : selectedCity,
        category: isThematic ? selectedCategory : selectedRegion,
        keyword: searchKeyword.trim() || null,
        total_discovered: data.total_discovered || 0,
        duplicates_filtered: data.duplicates_filtered || 0,
        search_params: {
          is_thematic: isThematic,
          skip_cache: skipCache,
          cuisine_region: !isThematic ? selectedRegion : undefined,
          search_theme: isThematic ? selectedCategory : undefined,
        },
        results: restaurants.map(r => ({ name: r.name, address: r.address, place_id: r.place_id, verified: r.google_verified })),
      }).then(() => queryClient.invalidateQueries({ queryKey: ["search-history"] }));
    } catch (e) {
      if (controller.signal.aborted) {
        toast({ title: "搜索已终止" });
        return;
      }
      toast({ title: "搜索失败", description: e instanceof Error ? e.message : "Unknown error", variant: "destructive" });
    } finally {
      abortControllerRef.current = null;
      setIsSearching(false);
    }
  };

  const handleStopSearch = () => {
    abortControllerRef.current?.abort();
    abortControllerRef.current = null;
    setIsSearching(false);
  };

  // ─── Import ───────────────────────────────────────────────────────────────
  const handleImport = async () => {
    if (selectedItems.size === 0) return;
    setIsImporting(true);
    setImportProgress({ current: 0, total: 0 });

    try {
      const selectedRestaurants = [...selectedItems].map(i => {
        const r = discovered[i];
        return {
          ...r,
          address: (r.google_verified === false && r.corrected_address) ? r.corrected_address : r.address,
        };
      });

      const batchSize = 20;
      const total = selectedRestaurants.length;
      setImportProgress({ current: 0, total });
      let totalImported = 0, totalFailed = 0, totalDuplicates = 0, totalCreated = 0, totalUpdated = 0;
      const allSuccessIds: string[] = [];
      const allDetails: Array<{ name: string; action?: string; error?: string; dedup_reason?: string; success: boolean }> = [];

      for (let i = 0; i < total; i += batchSize) {
        const batch = selectedRestaurants.slice(i, i + batchSize);
        const isThematic = selectedCategory !== "";
        const { data, error } = await supabase.functions.invoke("discover-asian-restaurants", {
          body: { mode: "import", restaurants: batch, country: selectedCountry, search_theme: isThematic ? selectedCategory : undefined },
        });

        if (error) {
          totalFailed += batch.length;
          batch.forEach(r => allDetails.push({ name: r.name, success: false, error: "request_failed" }));
        } else {
          totalImported += data.imported || 0;
          totalFailed += data.failed || 0;
          totalDuplicates += data.duplicates || 0;
          totalCreated += data.created || 0;
          totalUpdated += data.updated || 0;
          const batchIds = (data.results || []).filter((r: any) => r.success).map((r: any) => r.id);
          allSuccessIds.push(...batchIds);
          (data.results || []).forEach((r: any) => allDetails.push({ name: r.name, action: r.action, error: r.error, dedup_reason: r.dedup_reason, success: r.success }));
        }

        setImportProgress({ current: Math.min(i + batchSize, total), total });
        if (i + batchSize < total) await new Promise(r => setTimeout(r, 500));
      }

      setImportResults({ imported: totalImported, failed: totalFailed, duplicates: totalDuplicates, created: totalCreated, updated: totalUpdated, details: allDetails });
      setImportedIds(allSuccessIds);
      queryClient.invalidateQueries({ queryKey: ["admin-restaurants"] });
      toast({ title: "导入完成", description: `新增 ${totalCreated} | 更新 ${totalUpdated} | 重复跳过 ${totalDuplicates} | 失败 ${totalFailed - totalDuplicates}` });
    } catch (e) {
      toast({ title: "导入失败", description: e instanceof Error ? e.message : "Unknown error", variant: "destructive" });
    } finally {
      setIsImporting(false);
    }
  };

  // ─── Post-Import: Stories ─────────────────────────────────────────────────
  const handleGenerateStories = async () => {
    if (importedIds.length === 0) return;
    setIsGeneratingStories(true);
    setStoryProgress({ current: 0, total: importedIds.length });
    setStoryResult(null);

    const batchSize = 5;
    let processed = 0;
    for (let i = 0; i < importedIds.length; i += batchSize) {
      const batch = importedIds.slice(i, i + batchSize);
      const { data } = await supabase.functions.invoke("generate-store-stories", {
        body: { restaurant_ids: batch, mode: "story", no_brand: true },
      });
      processed += data?.updated || 0;
      setStoryProgress({ current: Math.min(i + batchSize, importedIds.length), total: importedIds.length });
      if (data?.processed === 0) break;
      await new Promise(r => setTimeout(r, 2000));
    }

    setStoryResult({ processed });
    setIsGeneratingStories(false);
    toast({ title: "✅ 故事生成完成", description: `${processed} 个` });
  };

  // ─── Post-Import: Photos ──────────────────────────────────────────────────
  const handleFetchPhotos = async () => {
    if (importedIds.length === 0) return;
    setIsFetchingPhotos(true);
    setPhotoProgress({ current: 0, total: importedIds.length });
    setPhotoResult(null);

    let success = 0, failed = 0;
    for (let i = 0; i < importedIds.length; i++) {
      try {
        const { data, error } = await supabase.functions.invoke("fetch-place-photos", {
          body: { restaurant_ids: [importedIds[i]], limit: 1, smart_filter: true },
        });
        if (!error && data?.results?.some((r: any) => r.status === "success" || r.status === "success_street_view")) {
          success++;
        } else {
          await new Promise(r => setTimeout(r, 3000));
          const { data: check } = await supabase.from("restaurants").select("image_url").eq("id", importedIds[i]).single();
          check?.image_url ? success++ : failed++;
        }
      } catch { failed++; }
      setPhotoProgress({ current: i + 1, total: importedIds.length });
      await new Promise(r => setTimeout(r, 500));
    }

    setPhotoResult({ success, failed });
    setIsFetchingPhotos(false);
    toast({ title: "✅ 照片抓取完成", description: `成功 ${success}，失败 ${failed}` });
  };

  // (Enrichment functions moved to DataCheckPanel)

  const toggleItem = (index: number) => {
    setSelectedItems(prev => {
      const next = new Set(prev);
      next.has(index) ? next.delete(index) : next.add(index);
      return next;
    });
  };

  const toggleAll = () => {
    selectedItems.size === discovered.length
      ? setSelectedItems(new Set())
      : setSelectedItems(new Set(discovered.map((_, i) => i)));
  };

  const getCategoryLabel = () => {
    return BUILDING_CATEGORIES.find(c => c.value === selectedCategory)?.label || "搜索";
  };

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Link to="/admin/restaurants">
            <Button variant="ghost" size="icon"><ArrowLeft className="h-5 w-5" /></Button>
          </Link>
          <div>
            <h1 className="text-2xl font-bold flex items-center gap-2">
              <Globe className="h-6 w-6" />
              全球建筑发现中心
            </h1>
            <p className="text-sm text-muted-foreground mt-0.5">
              Perplexity AI 发现 → Google Places 验证 → 自动去重 → 内容补全
            </p>
          </div>
        </div>
        {healthData && (
          <div className="hidden md:flex items-center gap-3 text-xs text-muted-foreground">
            <span className="flex items-center gap-1"><Database className="h-3.5 w-3.5" /> {healthData.total} 总计</span>
            <span className="flex items-center gap-1"><Landmark className="h-3.5 w-3.5" /> {healthData.landmarks} 地标</span>
            <span className="flex items-center gap-1"><Shield className="h-3.5 w-3.5 text-emerald-500" /> {healthData.hasPlaceId} 已验证</span>
          </div>
        )}
      </div>

      {/* Main Tabs */}
      <Tabs value={activeMainTab} onValueChange={setActiveMainTab}>
        <TabsList className="w-full justify-start flex-wrap">
          <TabsTrigger value="search" className="gap-1.5"><Search className="h-3.5 w-3.5" /> 手动搜索</TabsTrigger>
          <TabsTrigger value="michelin-import" className="gap-1.5"><Import className="h-3.5 w-3.5" /> 米其林导入</TabsTrigger>
          <TabsTrigger value="michelin-enrich" className="gap-1.5"><Brain className="h-3.5 w-3.5" /> 数据完善</TabsTrigger>
          <TabsTrigger value="pipeline" className="gap-1.5"><Zap className="h-3.5 w-3.5" /> 自动管线</TabsTrigger>
          <TabsTrigger value="datacheck" className="gap-1.5"><Shield className="h-3.5 w-3.5" /> 数据检查</TabsTrigger>
          <TabsTrigger value="history" className="gap-1.5"><History className="h-3.5 w-3.5" /> 搜索记录</TabsTrigger>
          <TabsTrigger value="health" className="gap-1.5"><BarChart3 className="h-3.5 w-3.5" /> 数据健康</TabsTrigger>
        </TabsList>

        {/* ═══ TAB: Michelin Import ═══ */}
        <TabsContent value="michelin-import" className="space-y-4 mt-4">
          <MichelinImportPanel />
        </TabsContent>

        {/* ═══ TAB: Michelin Enrichment ═══ */}
        <TabsContent value="michelin-enrich" className="space-y-4 mt-4">
          <MichelinEnrichmentPanel />
        </TabsContent>

        {/* ═══ TAB: Manual Search ═══ */}
        <TabsContent value="search" className="space-y-4 mt-4">
          {/* Category Selection */}
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-2">
            {BUILDING_CATEGORIES.map(cat => (
              <button
                key={cat.value}
                onClick={() => setSelectedCategory(cat.value)}
                className={`flex flex-col items-center gap-1 p-3 rounded-lg border-2 transition-all text-xs ${
                  selectedCategory === cat.value
                    ? "border-primary bg-primary/5 shadow-sm"
                    : "border-border hover:border-primary/40 hover:bg-muted/50"
                }`}
              >
                <cat.icon className={`h-5 w-5 ${selectedCategory === cat.value ? "text-primary" : "text-muted-foreground"}`} />
                <span className="font-medium text-center leading-tight">{cat.label}</span>
              </button>
            ))}
          </div>

          {/* Search Controls */}
          <Card>
            <CardContent className="pt-4 space-y-3">
              <div className="flex flex-col sm:flex-row gap-2">
                {selectedCategory === "" && (
                  <Select value={selectedRegion} onValueChange={setSelectedRegion}>
                    <SelectTrigger className="w-full sm:w-[140px]">
                      <SelectValue placeholder="选择菜系" />
                    </SelectTrigger>
                    <SelectContent>
                      {CUISINE_REGIONS.map(r => (
                        <SelectItem key={r.value} value={r.value}>{r.label}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                )}
                <Select value={selectedCountry} onValueChange={handleCountryChange}>
                  <SelectTrigger className="w-full sm:w-[140px]">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {COUNTRIES.map(c => (
                      <SelectItem key={c.code} value={c.code}>{c.flag} {c.label}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <Select value={selectedCity} onValueChange={setSelectedCity}>
                  <SelectTrigger className="w-full sm:w-[180px]">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">{countryConfig.flag} 全部城市</SelectItem>
                    {countryConfig.cities.map(city => (
                      <SelectItem key={city} value={city}>{city}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <Input
                  placeholder="关键词（可选）"
                  value={searchKeyword}
                  onChange={(e) => setSearchKeyword(e.target.value)}
                  className="flex-1"
                  onKeyDown={(e) => e.key === "Enter" && !isSearching && handleSearch()}
                />
                {isSearching ? (
                  <Button onClick={handleStopSearch} variant="destructive" className="shrink-0">
                    <StopCircle className="mr-1.5 h-4 w-4" />终止
                  </Button>
                ) : (
                  <Button onClick={handleSearch} className="shrink-0">
                    <Search className="mr-1.5 h-4 w-4" />搜索{getCategoryLabel()}
                  </Button>
                )}
              </div>
              <div className="flex items-center gap-3 text-xs text-muted-foreground">
                <div className="flex items-center gap-1.5">
                  <Switch id="skip-cache" checked={skipCache} onCheckedChange={setSkipCache} />
                  <Label htmlFor="skip-cache" className="text-xs cursor-pointer">跳过缓存</Label>
                </div>
                <span className="text-muted-foreground/60">•</span>
                <span>模板: <strong>{BUILDING_CATEGORIES.find(c => c.value === selectedCategory)?.template || "default"}</strong></span>
                <span className="text-muted-foreground/60">•</span>
                <span className="flex items-center gap-1"><Shield className="h-3 w-3 text-emerald-500" /> google_place_id 去重已启用</span>
              </div>
            </CardContent>
          </Card>

          {/* Loading state */}
          {isSearching && (
            <Card>
              <CardContent className="flex flex-col items-center justify-center py-10 gap-3">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
                <p className="text-sm text-muted-foreground">
                  正在搜索 {selectedCity === "all" ? `${countryConfig.flag} ${countryConfig.label}全境` : selectedCity} 的 {getCategoryLabel()}...
                </p>
                <p className="text-xs text-muted-foreground">Perplexity AI 发现 → Google Places 验证地址 + 获取 Place ID</p>
              </CardContent>
            </Card>
          )}

          {/* Search stats */}
          {searchStats && !isSearching && (
            <div className="grid grid-cols-2 sm:grid-cols-5 gap-2">
              <StatCard label="总发现" value={searchStats.total_discovered} icon={Search} />
              <StatCard label="已存在" value={searchStats.duplicates_filtered} icon={AlertCircle} color="text-yellow-600" />
              <StatCard label="新增" value={discovered.length} icon={CheckCircle2} color="text-emerald-600" />
              <StatCard label="已验证" value={searchStats.verified_count || 0} icon={Shield} color="text-emerald-600" />
              <StatCard label="缓存命中" value={searchStats.cache_hits || 0} icon={Database} color="text-blue-600" />
            </div>
          )}

          {searchStats?.search_error && (
            <div className="p-3 rounded-md bg-destructive/10 border border-destructive/20 text-sm text-destructive flex items-start gap-2">
              <AlertTriangle className="h-4 w-4 mt-0.5 flex-shrink-0" />
              <p className="text-xs">{searchStats.search_error}</p>
            </div>
          )}

          {/* Results list */}
          {discovered.length > 0 && !isSearching && (
            <Card>
              <CardHeader className="pb-2">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <Checkbox checked={selectedItems.size === discovered.length} onCheckedChange={toggleAll} />
                    <CardTitle className="text-sm">全选 ({selectedItems.size}/{discovered.length})</CardTitle>
                    <Badge variant="outline" className="text-[10px]">
                      {discovered.filter(r => r.place_id).length} 有 Place ID
                    </Badge>
                  </div>
                  <Button onClick={handleImport} disabled={isImporting || selectedItems.size === 0} size="sm">
                    {isImporting ? (
                      <><Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" />导入 {importProgress.current}/{importProgress.total}</>
                    ) : (
                      <><Import className="mr-1.5 h-3.5 w-3.5" />导入 ({selectedItems.size})</>
                    )}
                  </Button>
                </div>
                {isImporting && importProgress.total > 0 && (
                  <Progress value={(importProgress.current / importProgress.total) * 100} className="mt-2" />
                )}
              </CardHeader>
              <CardContent className="p-0">
                <ScrollArea className="h-[50vh]">
                  <div className="divide-y">
                    {discovered.map((r, i) => {
                      const isVerified = r.google_verified !== false;
                      return (
                        <div
                          key={i}
                          className={`flex items-start gap-3 px-4 py-2.5 hover:bg-muted/50 cursor-pointer transition-colors ${!isVerified ? "opacity-60" : ""}`}
                          onClick={() => toggleItem(i)}
                        >
                          <Checkbox checked={selectedItems.has(i)} className="mt-0.5" />
                          <div className="flex-1 min-w-0">
                            <div className="font-medium text-sm flex items-center gap-1.5">
                              {isVerified ? (
                                <CheckCircle2 className="h-3.5 w-3.5 text-emerald-500 flex-shrink-0" />
                              ) : (
                                <AlertTriangle className="h-3.5 w-3.5 text-destructive flex-shrink-0" />
                              )}
                              <span className="truncate">{r.name}</span>
                            </div>
                            <div className="text-xs text-muted-foreground flex items-center gap-1 mt-0.5">
                              <MapPin className="h-3 w-3 flex-shrink-0" />
                              <span className={`truncate ${!isVerified ? "line-through" : ""}`}>{r.address}</span>
                            </div>
                            {r.story_hint && (
                              <p className="text-[10px] text-muted-foreground/70 mt-0.5 line-clamp-1">{r.story_hint}</p>
                            )}
                          </div>
                          <div className="flex flex-col items-end gap-0.5 flex-shrink-0">
                            <Badge variant="secondary" className="text-[10px] h-5">{r.cuisine_type}</Badge>
                            <div className="flex items-center gap-0.5">
                              {r.source === "perplexity" && <Badge variant="outline" className="text-[9px] px-1 py-0 h-4 border-violet-300 text-violet-600">AI</Badge>}
                              {r.source === "firecrawl" && <Badge variant="outline" className="text-[9px] px-1 py-0 h-4 border-orange-300 text-orange-600">FC</Badge>}
                              {r.place_id && <Badge variant="outline" className="text-[9px] px-1 py-0 h-4 border-emerald-300 text-emerald-600">PID</Badge>}
                            </div>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </ScrollArea>
              </CardContent>
            </Card>
          )}

          {/* Import results & post-import actions */}
          {importResults && (
            <Card>
              <CardContent className="pt-4 space-y-3">
                {/* Summary stats */}
                <div className="flex items-center gap-3 flex-wrap text-sm">
                  {(importResults.created || 0) > 0 && (
                    <span className="text-emerald-600 font-medium">🆕 新增 {importResults.created}</span>
                  )}
                  {(importResults.updated || 0) > 0 && (
                    <span className="text-blue-600 font-medium">📝 更新 {importResults.updated}</span>
                  )}
                  {(importResults.duplicates || 0) > 0 && (
                    <span className="text-yellow-600 font-medium">🔄 重复跳过 {importResults.duplicates}</span>
                  )}
                  {importResults.failed - (importResults.duplicates || 0) > 0 && (
                    <span className="text-destructive font-medium">❌ 失败 {importResults.failed - (importResults.duplicates || 0)}</span>
                  )}
                </div>

                {/* Detailed per-item results (collapsible) */}
                {importResults.details && importResults.details.length > 0 && (
                  <details className="text-xs">
                    <summary className="cursor-pointer text-muted-foreground hover:text-foreground">
                      查看详情 ({importResults.details.length} 项)
                    </summary>
                    <div className="mt-2 max-h-48 overflow-y-auto space-y-1 border rounded-md p-2 bg-muted/30">
                      {importResults.details.map((d, idx) => (
                        <div key={idx} className="flex items-center gap-2">
                          <span>
                            {d.success && d.action === "created" && "🆕"}
                            {d.success && d.action === "updated" && "📝"}
                            {!d.success && d.error === "duplicate" && "🔄"}
                            {!d.success && d.error !== "duplicate" && "❌"}
                          </span>
                          <span className="font-medium truncate max-w-[200px]">{d.name}</span>
                          <span className="text-muted-foreground">
                            {d.success && d.action === "created" && "新增"}
                            {d.success && d.action === "updated" && "已更新地址/坐标"}
                            {!d.success && d.dedup_reason === "google_place_id" && "重复(Place ID)"}
                            {!d.success && d.dedup_reason === "name_address" && "重复(名称+地址)"}
                            {!d.success && d.dedup_reason === "google_place_id_constraint" && "重复(ID约束)"}
                            {!d.success && d.error && d.error !== "duplicate" && d.error}
                          </span>
                        </div>
                      ))}
                    </div>
                  </details>
                )}

                <div className="flex gap-2 flex-wrap">
                  {!storyResult && (
                    <Button variant="outline" size="sm" onClick={handleGenerateStories} disabled={isGeneratingStories || importedIds.length === 0}>
                      {isGeneratingStories ? <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" /> : <BookOpen className="mr-1.5 h-3.5 w-3.5" />}
                      生成故事 ({importedIds.length})
                    </Button>
                  )}
                  {storyResult && <Badge variant="secondary">✅ 故事 {storyResult.processed} 个</Badge>}

                  {!photoResult && (
                    <Button variant="outline" size="sm" onClick={handleFetchPhotos} disabled={isFetchingPhotos || importedIds.length === 0}>
                      {isFetchingPhotos ? <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" /> : <ImageIcon className="mr-1.5 h-3.5 w-3.5" />}
                      抓取照片 ({importedIds.length})
                    </Button>
                  )}
                  {photoResult && <Badge variant="secondary">📷 成功 {photoResult.success} 失败 {photoResult.failed}</Badge>}
                </div>

                {isGeneratingStories && storyProgress.total > 0 && (
                  <ProgressBar current={storyProgress.current} total={storyProgress.total} label="故事" />
                )}
                {isFetchingPhotos && photoProgress.total > 0 && (
                  <ProgressBar current={photoProgress.current} total={photoProgress.total} label="照片" />
                )}
              </CardContent>
            </Card>
          )}
        </TabsContent>

        {/* ═══ TAB: Auto Pipeline ═══ */}
        <TabsContent value="pipeline" className="mt-4">
          <DiscoveryPipelineDashboard />
        </TabsContent>

        {/* ═══ TAB: Search History ═══ */}
        <TabsContent value="history" className="mt-4">
          <SearchHistoryPanel />
        </TabsContent>

        {/* ═══ TAB: Data Check ═══ */}
        <TabsContent value="datacheck" className="mt-4">
          <DataCheckPanel />
        </TabsContent>

        {/* ═══ TAB: Data Health ═══ */}
        <TabsContent value="health" className="mt-4 space-y-4">
          <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
            <HealthCard label="总记录" value={healthData?.total || 0} icon={Database} />
            <HealthCard label="名胜古迹" value={healthData?.landmarks || 0} icon={Landmark} color="text-purple-600" />
            <HealthCard label="有 Place ID" value={healthData?.hasPlaceId || 0} icon={Shield} color="text-emerald-600"
              subtitle={healthData ? `${((healthData.hasPlaceId / healthData.total) * 100).toFixed(1)}%` : undefined} />
            <HealthCard label="零坐标" value={healthData?.zeroCoords || 0} icon={AlertTriangle}
              color={healthData?.zeroCoords ? "text-destructive" : "text-emerald-600"} />
            <HealthCard label="缺照片" value={healthData?.noPhoto || 0} icon={ImageIcon} color="text-yellow-600" />
          </div>

          <Card>
            <CardHeader>
              <CardTitle className="text-base flex items-center gap-2">
                <Shield className="h-4 w-4 text-emerald-500" />
                去重保护机制
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-3 text-sm">
                <div className="p-3 rounded-lg bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-200 dark:border-emerald-800">
                  <div className="font-medium text-emerald-700 dark:text-emerald-400 flex items-center gap-1.5">
                    <CheckCircle2 className="h-4 w-4" />
                    google_place_id 唯一约束
                  </div>
                  <p className="text-xs text-emerald-600 dark:text-emerald-500 mt-1">数据库层面阻止相同 Google 地点重复插入</p>
                </div>
                <div className="p-3 rounded-lg bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-200 dark:border-emerald-800">
                  <div className="font-medium text-emerald-700 dark:text-emerald-400 flex items-center gap-1.5">
                    <CheckCircle2 className="h-4 w-4" />
                    名称+地址模糊匹配
                  </div>
                  <p className="text-xs text-emerald-600 dark:text-emerald-500 mt-1">导入时自动对比现有数据的名称和地址相似度</p>
                </div>
                <div className="p-3 rounded-lg bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-200 dark:border-emerald-800">
                  <div className="font-medium text-emerald-700 dark:text-emerald-400 flex items-center gap-1.5">
                    <CheckCircle2 className="h-4 w-4" />
                    Google Places 验证
                  </div>
                  <p className="text-xs text-emerald-600 dark:text-emerald-500 mt-1">搜索结果通过 Google Places API 验证地址和坐标</p>
                </div>
              </div>

              <Button variant="outline" size="sm" onClick={() => refetchHealth()}>
                <RefreshCw className="mr-1.5 h-3.5 w-3.5" /> 刷新数据
              </Button>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

// ─── Reusable Sub-components ────────────────────────────────────────────────
function StatCard({ label, value, icon: Icon, color }: { label: string; value: number; icon: any; color?: string }) {
  return (
    <div className="flex items-center gap-2 p-3 rounded-lg bg-muted/50 border">
      <Icon className={`h-4 w-4 ${color || "text-muted-foreground"}`} />
      <div>
        <div className="text-lg font-bold text-foreground">{value}</div>
        <div className="text-[10px] text-muted-foreground">{label}</div>
      </div>
    </div>
  );
}

function HealthCard({ label, value, icon: Icon, color, subtitle }: { label: string; value: number; icon: any; color?: string; subtitle?: string }) {
  return (
    <Card>
      <CardContent className="pt-4 pb-3 px-4">
        <div className="flex items-center gap-2">
          <Icon className={`h-5 w-5 ${color || "text-muted-foreground"}`} />
          <div className="text-2xl font-bold text-foreground">{value}</div>
        </div>
        <div className="text-xs text-muted-foreground mt-1">{label}</div>
        {subtitle && <div className="text-[10px] text-muted-foreground/60 mt-0.5">{subtitle}</div>}
      </CardContent>
    </Card>
  );
}

function ProgressBar({ current, total, label }: { current: number; total: number; label: string }) {
  return (
    <div className="space-y-1">
      <Progress value={(current / total) * 100} />
      <div className="text-xs text-muted-foreground">{label}: {current}/{total}</div>
    </div>
  );
}
