import { useState } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Separator } from "@/components/ui/separator";
import {
  Loader2, Search, Brain, Phone, Mail, Globe, ChefHat, Star,
  ExternalLink, Clock, Users, Award, DollarSign, CheckCircle2,
  AlertCircle, Instagram, Facebook, Twitter, RefreshCw,
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";

const COUNTRIES = [
  { code: "all", label: "全部国家" },
  { code: "Portugal", label: "🇵🇹 葡萄牙" },
  { code: "Spain", label: "🇪🇸 西班牙" },
  { code: "France", label: "🇫🇷 法国" },
  { code: "Italy", label: "🇮🇹 意大利" },
  { code: "Germany", label: "🇩🇪 德国" },
  { code: "United Kingdom", label: "🇬🇧 英国" },
  { code: "Japan", label: "🇯🇵 日本" },
  { code: "United States", label: "🇺🇸 美国" },
];

const MICHELIN_LABELS: Record<string, string> = {
  '3': '⭐⭐⭐ 三星',
  '2': '⭐⭐ 二星',
  '1': '⭐ 一星',
  'bib_gourmand': '🍽️ 必比登',
  'selected': '🌟 入选',
};

interface MichelinRestaurant {
  id: string;
  name: string;
  name_en: string | null;
  city: string | null;
  country: string | null;
  michelin_stars: string | null;
  phone: string | null;
  email: string | null;
  website_url: string | null;
  chef_name: string | null;
  chef_email: string | null;
  chef_phone: string | null;
  price_range: string | null;
  avg_price_per_person: string | null;
  enriched_at: string | null;
  enrichment_data: any;
  michelin_url: string | null;
  rating: number | null;
  address: string;
}

export default function MichelinEnrichmentPanel() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [country, setCountry] = useState("Portugal");
  const [searchTerm, setSearchTerm] = useState("");
  const [enrichFilter, setEnrichFilter] = useState("all");
  const [loading, setLoading] = useState(false);
  const [batchLoading, setBatchLoading] = useState(false);
  const [selectedRestaurant, setSelectedRestaurant] = useState<MichelinRestaurant | null>(null);
  const [detailOpen, setDetailOpen] = useState(false);

  const { data: restaurants, isLoading } = useQuery({
    queryKey: ["michelin-enrichment", country, searchTerm, enrichFilter],
    queryFn: async () => {
      let query = supabase
        .from('restaurants')
        .select('id, name, name_en, city, country, michelin_stars, phone, email, website_url, chef_name, chef_email, chef_phone, price_range, avg_price_per_person, enriched_at, enrichment_data, michelin_url, rating, address')
        .not('michelin_stars', 'is', null)
        .eq('visible', true)
        .order('michelin_stars', { ascending: true })
        .order('name', { ascending: true });

      if (country && country !== 'all') query = query.eq('country', country);
      if (searchTerm) query = query.or(`name.ilike.%${searchTerm}%,name_en.ilike.%${searchTerm}%,city.ilike.%${searchTerm}%`);
      if (enrichFilter === 'enriched') query = query.not('enriched_at', 'is', null);
      if (enrichFilter === 'pending') query = query.is('enriched_at', null);

      const { data, error } = await query.limit(500);
      if (error) throw error;
      return (data as unknown as MichelinRestaurant[]) || [];
    },
  });

  const handleEnrichSingle = async (restaurantId: string) => {
    setLoading(true);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) throw new Error("Not authenticated");

      const res = await supabase.functions.invoke("enrich-michelin-restaurant", {
        body: { restaurant_id: restaurantId },
      });

      if (res.error) throw res.error;
      if (!res.data?.success) throw new Error(res.data?.error || 'Enrichment failed');

      toast({ title: "数据完善成功", description: `已获取 ${res.data.enrichment?.chef_name || '餐厅'} 的详细信息` });
      queryClient.invalidateQueries({ queryKey: ["michelin-enrichment"] });

      // Refresh detail dialog if open
      if (selectedRestaurant?.id === restaurantId) {
        const updated = restaurants?.find(r => r.id === restaurantId);
        if (updated) {
          setSelectedRestaurant({ ...updated, ...res.data.enrichment, enriched_at: new Date().toISOString(), enrichment_data: res.data.enrichment });
        }
      }
    } catch (err: any) {
      toast({ title: "完善失败", description: err.message, variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  const handleBatchEnrich = async () => {
    setBatchLoading(true);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) throw new Error("Not authenticated");

      const res = await supabase.functions.invoke("enrich-michelin-restaurant", {
        body: { batch: true, country: country === 'all' ? undefined : country, limit: 5 },
      });

      if (res.error) throw res.error;
      if (!res.data?.success) throw new Error(res.data?.error || 'Batch enrichment failed');

      toast({
        title: `批量完善完成`,
        description: `成功 ${res.data.succeeded}/${res.data.total} 家`,
      });
      queryClient.invalidateQueries({ queryKey: ["michelin-enrichment"] });
    } catch (err: any) {
      toast({ title: "批量完善失败", description: err.message, variant: "destructive" });
    } finally {
      setBatchLoading(false);
    }
  };

  const openDetail = (restaurant: MichelinRestaurant) => {
    setSelectedRestaurant(restaurant);
    setDetailOpen(true);
  };

  const enrichedCount = restaurants?.filter(r => r.enriched_at).length || 0;
  const totalCount = restaurants?.length || 0;

  return (
    <>
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Brain className="h-5 w-5" />
            米其林餐厅数据完善
          </CardTitle>
          <CardDescription>
            使用 AI 搜索补全餐厅联系方式、主厨信息、评分、价格等数据
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          {/* Filters */}
          <div className="flex flex-wrap items-center gap-3">
            <Select value={country} onValueChange={setCountry}>
              <SelectTrigger className="w-[160px]">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {COUNTRIES.map(c => (
                  <SelectItem key={c.code} value={c.code}>{c.label}</SelectItem>
                ))}
              </SelectContent>
            </Select>
            <Select value={enrichFilter} onValueChange={setEnrichFilter}>
              <SelectTrigger className="w-[140px]">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">全部</SelectItem>
                <SelectItem value="enriched">已完善</SelectItem>
                <SelectItem value="pending">待完善</SelectItem>
              </SelectContent>
            </Select>
            <div className="relative flex-1 min-w-[200px]">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input
                className="pl-9"
                placeholder="搜索餐厅名称或城市..."
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
              />
            </div>
            <Button
              onClick={handleBatchEnrich}
              disabled={batchLoading}
              variant="outline"
            >
              {batchLoading ? <Loader2 className="h-4 w-4 animate-spin mr-1" /> : <RefreshCw className="h-4 w-4 mr-1" />}
              批量完善 (5家)
            </Button>
          </div>

          {/* Stats */}
          <div className="flex gap-3">
            <Badge variant="outline" className="gap-1">
              总计 {totalCount}
            </Badge>
            <Badge variant="secondary" className="gap-1 bg-emerald-500/15 text-emerald-700 border-emerald-500/30">
              <CheckCircle2 className="h-3 w-3" /> 已完善 {enrichedCount}
            </Badge>
            <Badge variant="secondary" className="gap-1 bg-amber-500/15 text-amber-700 border-amber-500/30">
              <AlertCircle className="h-3 w-3" /> 待完善 {totalCount - enrichedCount}
            </Badge>
          </div>

          {/* Table */}
          {isLoading ? (
            <div className="flex items-center justify-center py-8">
              <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
            </div>
          ) : (
            <div className="border rounded-lg overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead className="bg-muted/50">
                    <tr>
                      <th className="text-left p-3 font-medium">餐厅</th>
                      <th className="text-left p-3 font-medium">星级</th>
                      <th className="text-left p-3 font-medium">城市</th>
                      <th className="text-left p-3 font-medium">主厨</th>
                      <th className="text-left p-3 font-medium">联系方式</th>
                      <th className="text-left p-3 font-medium">状态</th>
                      <th className="text-right p-3 font-medium">操作</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y">
                    {restaurants?.map(r => (
                      <tr key={r.id} className="hover:bg-muted/30 transition-colors">
                        <td className="p-3">
                          <div className="font-medium truncate max-w-[200px]">{r.name}</div>
                          {r.name_en && r.name_en !== r.name && (
                            <div className="text-xs text-muted-foreground truncate max-w-[200px]">{r.name_en}</div>
                          )}
                        </td>
                        <td className="p-3">
                          <Badge variant="outline" className="text-[10px] whitespace-nowrap">
                            {MICHELIN_LABELS[r.michelin_stars || ''] || r.michelin_stars}
                          </Badge>
                        </td>
                        <td className="p-3 text-muted-foreground text-xs">{r.city}</td>
                        <td className="p-3">
                          {r.chef_name ? (
                            <span className="text-xs">{r.chef_name}</span>
                          ) : (
                            <span className="text-xs text-muted-foreground">-</span>
                          )}
                        </td>
                        <td className="p-3">
                          <div className="flex gap-1">
                            {r.phone && <Phone className="h-3 w-3 text-emerald-500" />}
                            {r.email && <Mail className="h-3 w-3 text-blue-500" />}
                            {r.website_url && <Globe className="h-3 w-3 text-purple-500" />}
                            {!r.phone && !r.email && !r.website_url && (
                              <span className="text-xs text-muted-foreground">-</span>
                            )}
                          </div>
                        </td>
                        <td className="p-3">
                          {r.enriched_at ? (
                            <Badge variant="secondary" className="text-[10px] bg-emerald-500/15 text-emerald-700">已完善</Badge>
                          ) : (
                            <Badge variant="secondary" className="text-[10px] bg-amber-500/15 text-amber-700">待完善</Badge>
                          )}
                        </td>
                        <td className="p-3 text-right">
                          <div className="flex items-center justify-end gap-1">
                            <Button
                              size="sm"
                              variant="ghost"
                              className="h-7 text-xs"
                              onClick={() => openDetail(r)}
                            >
                              详情
                            </Button>
                            <Button
                              size="sm"
                              variant="outline"
                              className="h-7 text-xs"
                              onClick={() => handleEnrichSingle(r.id)}
                              disabled={loading}
                            >
                              {loading ? <Loader2 className="h-3 w-3 animate-spin" /> : <Brain className="h-3 w-3" />}
                            </Button>
                          </div>
                        </td>
                      </tr>
                    ))}
                    {restaurants?.length === 0 && (
                      <tr>
                        <td colSpan={7} className="p-8 text-center text-muted-foreground">
                          没有找到匹配的米其林餐厅
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Detail Dialog */}
      <Dialog open={detailOpen} onOpenChange={setDetailOpen}>
        <DialogContent className="max-w-2xl max-h-[85vh]">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <ChefHat className="h-5 w-5" />
              {selectedRestaurant?.name}
              {selectedRestaurant?.michelin_stars && (
                <Badge variant="outline" className="ml-2">
                  {MICHELIN_LABELS[selectedRestaurant.michelin_stars] || selectedRestaurant.michelin_stars}
                </Badge>
              )}
            </DialogTitle>
          </DialogHeader>
          <ScrollArea className="max-h-[65vh] pr-4">
            {selectedRestaurant && <RestaurantDetailContent restaurant={selectedRestaurant} />}
          </ScrollArea>
          <div className="flex justify-end gap-2 pt-2">
            <Button
              variant="outline"
              size="sm"
              onClick={() => selectedRestaurant && handleEnrichSingle(selectedRestaurant.id)}
              disabled={loading}
            >
              {loading ? <Loader2 className="h-4 w-4 animate-spin mr-1" /> : <Brain className="h-4 w-4 mr-1" />}
              {selectedRestaurant?.enriched_at ? '重新获取' : '获取数据'}
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </>
  );
}

function RestaurantDetailContent({ restaurant }: { restaurant: MichelinRestaurant }) {
  const ed = restaurant.enrichment_data || {};

  const InfoRow = ({ icon: Icon, label, value, isLink }: { icon: any; label: string; value?: string | null; isLink?: boolean }) => {
    if (!value) return null;
    return (
      <div className="flex items-start gap-3 py-2">
        <Icon className="h-4 w-4 mt-0.5 text-muted-foreground shrink-0" />
        <div className="min-w-0">
          <div className="text-xs text-muted-foreground">{label}</div>
          {isLink ? (
            <a href={value} target="_blank" rel="noopener noreferrer" className="text-sm text-primary hover:underline break-all flex items-center gap-1">
              {value} <ExternalLink className="h-3 w-3 shrink-0" />
            </a>
          ) : (
            <div className="text-sm break-all">{value}</div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-4">
      {/* Basic Info */}
      <div>
        <h4 className="text-sm font-semibold mb-2 flex items-center gap-2">
          <Globe className="h-4 w-4" /> 餐厅信息
        </h4>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-x-6 border rounded-lg p-3 bg-muted/20">
          <InfoRow icon={Phone} label="电话" value={restaurant.phone} />
          <InfoRow icon={Mail} label="邮箱" value={restaurant.email || ed.restaurant_email} />
          <InfoRow icon={Globe} label="官网" value={restaurant.website_url || ed.website_url} isLink />
          <InfoRow icon={ExternalLink} label="米其林指南" value={restaurant.michelin_url || ed.michelin_url} isLink />
          <InfoRow icon={DollarSign} label="价位" value={restaurant.price_range || ed.price_range} />
          <InfoRow icon={DollarSign} label="人均" value={restaurant.avg_price_per_person || ed.avg_price_per_person} />
          <InfoRow icon={Star} label="Google评分" value={ed.rating_google?.toString()} />
          <InfoRow icon={Star} label="TripAdvisor评分" value={ed.rating_tripadvisor?.toString()} />
          <InfoRow icon={Clock} label="营业时间" value={ed.opening_hours_text} />
          <InfoRow icon={Users} label="座位数" value={ed.seating_capacity} />
          <InfoRow icon={Award} label="成立年份" value={ed.year_established} />
          <InfoRow icon={Award} label="着装要求" value={ed.dress_code} />
        </div>
      </div>

      <Separator />

      {/* Chef Info */}
      <div>
        <h4 className="text-sm font-semibold mb-2 flex items-center gap-2">
          <ChefHat className="h-4 w-4" /> 主厨信息
        </h4>
        <div className="border rounded-lg p-3 bg-muted/20">
          <InfoRow icon={ChefHat} label="主厨" value={restaurant.chef_name || ed.chef_name} />
          <InfoRow icon={Mail} label="主厨邮箱" value={restaurant.chef_email || ed.chef_email} />
          <InfoRow icon={Phone} label="主厨电话" value={restaurant.chef_phone || ed.chef_phone} />
        </div>
      </div>

      {/* Social Media */}
      {ed.social_media && (ed.social_media.instagram || ed.social_media.facebook || ed.social_media.twitter) && (
        <>
          <Separator />
          <div>
            <h4 className="text-sm font-semibold mb-2">社交媒体</h4>
            <div className="border rounded-lg p-3 bg-muted/20">
              <InfoRow icon={Instagram} label="Instagram" value={ed.social_media.instagram} isLink={ed.social_media.instagram?.startsWith('http')} />
              <InfoRow icon={Facebook} label="Facebook" value={ed.social_media.facebook} isLink />
              <InfoRow icon={Twitter} label="Twitter" value={ed.social_media.twitter} isLink={ed.social_media.twitter?.startsWith('http')} />
            </div>
          </div>
        </>
      )}

      {/* Cuisine & Awards */}
      {(ed.cuisine_types?.length > 0 || ed.awards?.length > 0) && (
        <>
          <Separator />
          <div className="space-y-2">
            {ed.cuisine_types?.length > 0 && (
              <div>
                <span className="text-xs text-muted-foreground">菜系: </span>
                <div className="flex flex-wrap gap-1 mt-1">
                  {ed.cuisine_types.map((c: string, i: number) => (
                    <Badge key={i} variant="outline" className="text-[10px]">{c}</Badge>
                  ))}
                </div>
              </div>
            )}
            {ed.awards?.length > 0 && (
              <div>
                <span className="text-xs text-muted-foreground">其他奖项: </span>
                <div className="flex flex-wrap gap-1 mt-1">
                  {ed.awards.map((a: string, i: number) => (
                    <Badge key={i} variant="secondary" className="text-[10px]">{a}</Badge>
                  ))}
                </div>
              </div>
            )}
          </div>
        </>
      )}

      {/* Summary */}
      {ed.summary && (
        <>
          <Separator />
          <div>
            <h4 className="text-sm font-semibold mb-1">简介</h4>
            <p className="text-sm text-muted-foreground">{ed.summary}</p>
          </div>
        </>
      )}

      {/* Enrichment status */}
      <Separator />
      <div className="text-xs text-muted-foreground">
        {restaurant.enriched_at ? (
          <span className="flex items-center gap-1">
            <CheckCircle2 className="h-3 w-3 text-emerald-500" />
            最后更新: {new Date(restaurant.enriched_at).toLocaleString('zh-CN')}
          </span>
        ) : (
          <span className="flex items-center gap-1">
            <AlertCircle className="h-3 w-3 text-amber-500" />
            尚未获取详细数据，点击"获取数据"按钮开始
          </span>
        )}
      </div>
    </div>
  );
}
